final:
module JK_latch (  
    input obf_J,  
    input K,  
    input clk,  
    output reg Q  
);  
    always @(posedge clk) begin  
        if (obf_J && !K)  
            Q <= 1;  
        else if (!obf_J && K)  
            Q <= 0;  
        else if (obf_J && K)  
            Q <= ~Q;  
        // If both obf_J and K are low, Q remains the same  
    end  
endmodule
